query:
UPDATE products SET isFeatured = 1 
WHERE id IN (
  SELECT id FROM (
    SELECT id FROM products 
    WHERE isVisible = 1 AND stockQuantity > 0
    ORDER BY stockQuantity DESC, customerPriceUSD DESC
    LIMIT 12
  ) AS top_products
);
SELECT COUNT(*) as featured_count FROM products WHERE isFeatured = 1;

